request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gw ?gwType ?gwDir ?gwName
       (GROUP_CONCAT(DISTINCT ?srcName; separator=", ") AS ?incomingFrom)
       (GROUP_CONCAT(DISTINCT ?tgtName; separator=", ") AS ?outgoingTo)
WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "0b4394edaa09437d93cc54c78c0180cb" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?gw a ?gwType .
  ?gw tai:belongsTo ?choreo .
  FILTER(?gwType IN (bboExt:ParallelGateway, bboExt:ExclusiveGateway, bboExt:EventBasedGateway))
  OPTIONAL { ?gw bboExt:gatewayDirection ?gwDir . }
  OPTIONAL { ?gw bbo:name ?gwName . }
  OPTIONAL {
    ?inEdge a bbo:SequenceFlow .
    ?inEdge bbo:has_targetRef ?gw .
    ?inEdge bbo:has_sourceRef ?inSrc .
    OPTIONAL { ?inSrc bbo:name ?srcName . }
  }
  OPTIONAL {
    ?outEdge a bbo:SequenceFlow .
    ?outEdge bbo:has_sourceRef ?gw .
    ?outEdge bbo:has_targetRef ?outTgt .
    OPTIONAL { ?outTgt bbo:name ?tgtName . }
  }
}
GROUP BY ?gw ?gwType ?gwDir ?gwName
